707	
708	// ── Function collection and classification ──────────────────
709	
710	/// Harvest locally-defined function names from one source into `out`. Matches
711	/// both `name() {` and `function name` forms.
712	pub(crate) fn zrbtdru_collect_functions(src: &str, out: &mut BTreeSet<String>) {
713	    for raw in src.lines() {
714	        let trimmed = raw.trim_start();
715	        let rest = if let Some(after) = trimmed.strip_prefix("function ") {
716	            after.trim_start()
717	        } else {
718	            trimmed
719	        };
720	        let mut name = String::new();
721	        for ch in rest.chars() {
722	            if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
723	                name.push(ch);
724	            } else {
725	                break;
726	            }
727	        }
728	        if name.is_empty() {
729	            continue;
730	        }
731	        let after_name = rest[name.len()..].trim_start();
732	        if after_name.starts_with("()") || trimmed.starts_with("function ") {
733	            out.insert(name);
734	        }
735	    }
736	}
737	
738	/// Classify a command-position token. Returns `Some(detail)` when it violates
739	/// the domain's discipline, `None` when it is permitted. Dynamic tokens
740	/// (containing an expansion or quote) cannot be statically named and are
741	/// skipped.
742	pub(crate) fn zrbtdru_classify(
743	    command: &str,
744	    locals: &BTreeSet<String>,
745	    domain: zrbtdru_Domain,
746	) -> Option<String> {
747	    if command.is_empty() {
748	        return None;
749	    }
750	    if command.contains('$')
751	        || command.contains('`')
752	        || command.contains('"')
753	        || command.contains('\'')
754	    {
755	        return None;
756	    }
757	    let base = command.rsplit('/').next().unwrap_or(command);
758	    if ZRBTDRU_BUILTINS.contains(&base) {
759	        return None;
760	    }
761	    if locals.contains(command) || locals.contains(base) {
762	        return None;
763	    }
764	    // POSIX floor is universal — cleared in both domains.
765	    if ZRBTDRU_POSIX_FLOOR.contains(&base) {
766	        return None;
767	    }
768	    match domain {
769	        zrbtdru_Domain::Kit => {
770	            if ZRBTDRU_DECLARED_DEPS.contains(&base) {
771	                return None;
772	            }
773	            for ev in ZRBTDRU_EVICTIONS {
774	                if ev.command == base {
775	                    return Some(format!("evicted command — use {}", ev.replacement));
776	                }
777	            }
778	            Some("unknown command — not in POSIX floor or RBS0 declared dependencies".to_string())
779	        }
780	        zrbtdru_Domain::Gcb => {
781	            // No declared-dep inheritance and no eviction free-pass: GCB-bash is
782	            // held to floor ∪ the curated container-tool list (supply-chain).
783	            if ZRBTDRU_GCB_ALLOWED.contains(&base) {
784	                return None;
785	            }
786	            Some("unknown command — not in the curated GCB container-tool allowlist".to_string())
787	        }
788	    }
789	}
790	
791	/// True when `command` names an external command in the corpus's surface — a
792	/// static token that is neither a bash builtin nor a locally-defined function.
793	/// This is the classification-independent inventory predicate: it admits the
794	/// union of allowed externals (floor / declared / gcb-extra / tolerated
795	/// evictions) AND violations. Dynamic tokens (expansion or quote) cannot be
796	/// statically named and are excluded.
797	fn zrbtdru_is_external(command: &str, locals: &BTreeSet<String>) -> bool {
798	    if command.is_empty()
799	        || command.contains('$')
