            let shape_ok = matches!(tokens.get(i + 1), Some((_, zrbtdru_PyToken::Punct('.'))))
                && matches!(tokens.get(i + 2), Some((_, zrbtdru_PyToken::Ident(_))))
                && matches!(tokens.get(i + 3), Some((_, zrbtdru_PyToken::Punct('('))))
